my $name = "Ada";
my @nums = (10, 20, 30);
my %ages = (ada => 36, alan => 41);

print $name, "\n";        # scalar
print $nums[0], "\n";      # 10  (single element -> $)
print $ages{ada}, "\n";    # 36  (single value -> $)
print "@nums\n";           # 10 20 30 (whole array)

my @nums = (5, 6, 7, 8);

my $count = @nums;        # scalar context -> 4
my ($first) = @nums;      # list context  -> 5

print "count=$count\n";
print "first=$first\n";

# Force scalar context explicitly
print "size=", scalar(@nums), "\n";

my $line = "2026-07-03 ERROR disk full";

if ($line =~ /^(\d{4})-(\d{2})-(\d{2})\s+(\w+)/) {
    print "year=$1 month=$2 level=$4\n";
}

# Named captures
if ($line =~ /(?<level>ERROR|WARN|INFO)/) {
    print "level=$+{level}\n";
}

my $s = "Hello World";

