use strict;
our $VERSION = "1.0";       # package global

sub read_all {
    my $fh = shift;           # lexical, block-scoped
    local $/ = undef;         # temporarily slurp mode
    return <$fh>;             # $/ restored after sub returns
}

use strict;
use warnings;

sub greet {
    my ($name, $greeting) = @_;
    $greeting //= "Hello";
    return "$greeting, $name!";
}

sub total {
    my $sum = 0;
    $sum += $_ for @_;   # any number of args
    return $sum;
}

print greet("Ada"), "\n";
print total(1, 2, 3, 4), "\n";

# usage: perl script.pl file1 file2
print "Running $0 with @ARGV\n";

while (<>) {          # reads lines from @ARGV files or STDIN
    chomp;            # operates on $_
    print "$.: $_\n" if /error/i;   # $. is line number
}

use strict;

sub matches {
    my @found = grep { $_ > 10 } @_;
    return wantarray ? @found : scalar @found;
}

my @list  = matches(3, 12, 20);   # list context -> (12, 20)
my $count = matches(3, 12, 20);   # scalar context -> 2
print "@list / $count\n";

